<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1"><?=e($estimate['estimate_number'])?></h1><p class="text-muted mb-0"><?=e($estimate['display_name'])?> · <?=e($estimate['status'])?></p></div><div class="d-flex flex-wrap gap-2"><form method="post" action="/portal/estimates/<?=$estimate['id']?>/pdf"><?=csrf_field()?><button class="btn btn-outline-secondary"><i class="fa-solid fa-file-pdf"></i> Generate PDF</button></form><?php if($estimate['status']!=='accepted'):?><form method="post" action="/portal/estimates/<?=$estimate['id']?>/send"><?=csrf_field()?><button class="btn btn-outline-primary"><i class="fa-solid fa-envelope"></i> Send</button></form><form method="post" action="/portal/estimates/<?=$estimate['id']?>/accept"><?=csrf_field()?><button class="btn btn-success"><i class="fa-solid fa-check"></i> Accept & Create Job</button></form><?php endif?></div></div>
